#[test]
fn v16_bpf_auth_mark_target_effective_lag_counts_toward_liquidation_health() {
    const INITIAL_MARK: u64 = 100_000_000;
    const TARGET_MARK: u64 = 90_000_000;
    const EXPECTED_EFFECTIVE_AFTER_ONE_SLOT: u64 = 99_760_000;

    let mut env = V16CuEnv::new_with_market_params_and_price_move(1, 10_000, 10_000, 24);
    env.svm.warp_to_slot(1);
    env.configure_auth_mark_with_cu(1, INITIAL_MARK);

    let long_owner = Keypair::new();
    let short_owner = Keypair::new();
    let long_portfolio = env.create_portfolio(&long_owner);
    let short_portfolio = env.create_portfolio(&short_owner);
    env.deposit(&long_owner, long_portfolio, 100_000_000);
    env.deposit(&short_owner, short_portfolio, 200_000_000);
    env.trade_with_cu(
        &long_owner,
        long_portfolio,
        &short_owner,
        short_portfolio,
        POS_SCALE as i128,
        INITIAL_MARK,
        0,
    );

    env.svm.warp_to_slot(2);
    env.push_auth_mark_with_cu(2, TARGET_MARK);
    env.crank(
        long_portfolio,
        ProgInstruction::PermissionlessCrank {
            action: 0,
            asset_index: 0,
            now_slot: 2,
            funding_rate_e9: 0,
            close_q: 0,
            fee_bps: 0,
            recovery_reason: 0,
        },
    );

    let (_, lagged_group) = env.market_state();
    assert_eq!(
        lagged_group.assets[0].raw_oracle_target_price, TARGET_MARK,
        "AuthMark stores the un-clamped target for health certification"
    );
    assert_eq!(
        lagged_group.assets[0].effective_price, EXPECTED_EFFECTIVE_AFTER_ONE_SLOT,
        "effective price should be clamp-lagged by one 24 bps slot"
    );

    let lagged_long = env.portfolio_state(long_portfolio);
    assert!(
        lagged_long.health_cert.valid,
        "refresh must write a health certificate"
    );
    assert!(
        lagged_long.health_cert.certified_maintenance_req > INITIAL_MARK as u128,
        "maintenance must include the adverse target/effective lag penalty"
    );
    assert!(
        lagged_long.health_cert.certified_liq_deficit > 0,
        "lagged adverse AuthMark target must make the under-margined long liquidatable"
    );

    env.crank(
        long_portfolio,
        ProgInstruction::PermissionlessCrank {
            action: 1,
            asset_index: 0,
            now_slot: 2,
            funding_rate_e9: 0,
            close_q: POS_SCALE,
            fee_bps: 0,
            recovery_reason: 0,
        },
    );
    let liquidated_long = env.portfolio_state(long_portfolio);
    assert!(
        !has_active_leg_for_asset(&liquidated_long, 0),
        "positive lag-deficit certification must allow permissionless liquidation"
    );
}

#[test]
fn v16_cu_crank_cost_is_account_local_after_many_portfolios() {
    let mut env = V16CuEnv::new();
    let owner = Keypair::new();
    let portfolio = env.create_portfolio(&owner);
    env.deposit(&owner, portfolio, 1_000_000);

    let before_extra = env.crank(
        portfolio,
        ProgInstruction::PermissionlessCrank {
            action: 0,
            asset_index: 0,
            now_slot: 1,
            funding_rate_e9: 0,
            close_q: 0,
            fee_bps: 0,
            recovery_reason: 0,
        },
    );
    for _ in 0..64 {
        let owner = Keypair::new();
        let p = env.create_portfolio(&owner);
        let acct = env.svm.get_account(&p).expect("portfolio account exists");
        let (_header, parsed_owner) = state::read_portfolio_owner_preflight(&acct.data).unwrap();
        assert_eq!(parsed_owner, owner.pubkey().to_bytes());
    }

    let after_extra = env.crank(
        portfolio,
        ProgInstruction::PermissionlessCrank {
            action: 0,
            asset_index: 0,
            now_slot: 2,
            funding_rate_e9: 0,
            close_q: 0,
            fee_bps: 0,
            recovery_reason: 0,
        },
    );
    println!(
        "v16 refresh crank CU before extra portfolios: {before_extra}, after 64 extras: {after_extra}"
    );

    assert!(after_extra <= CRANK_CU_LIMIT);
    assert!(
        after_extra.saturating_sub(before_extra) < 10_000,
        "v16 crank should stay account-local rather than scaling with materialized portfolio count"
    );
}

#[test]
fn v16_bpf_policy_authority_and_base_unit_tags_are_bounded_and_persist() {
    let mut env = V16CuEnv::new();

    let liquidation_cu = env.update_liquidation_fee_policy_with_cu(1_234);
    assert_cu_within(
        "UpdateLiquidationFeePolicy",
        liquidation_cu,
        CUSTODY_CU_LIMIT,
    );
    let (cfg, _) = env.market_state();
    assert_eq!(cfg.liquidation_cranker_fee_share_bps, 1_234);

    let maintenance_cu = env.update_maintenance_fee_policy_with_cu(2_345);
    assert_cu_within(
        "UpdateMaintenanceFeePolicy",
        maintenance_cu,
        CUSTODY_CU_LIMIT,
    );
    let (cfg, _) = env.market_state();
    assert_eq!(cfg.maintenance_cranker_fee_share_bps, 2_345);

    let backing_cu = env.update_backing_fee_policy_with_cu(0, 77, 5_000);
    assert_cu_within("UpdateBackingFeePolicy", backing_cu, CUSTODY_CU_LIMIT);
    let (cfg, _) = env.market_state();
    assert_eq!(cfg.backing_trade_fee_bps_long, 77);
    assert_eq!(cfg.backing_trade_fee_insurance_share_bps_long, 5_000);
    assert_eq!(cfg.backing_trade_fee_policy_count, 1);

    let trade_fee_cu = env.update_trade_fee_policy_with_cu(88);
    assert_cu_within("UpdateTradeFeePolicy", trade_fee_cu, CUSTODY_CU_LIMIT);
    let (cfg, _) = env.market_state();
    assert_eq!(cfg.trade_fee_base_bps, 88);

    let redirect_cu = env.update_fee_redirect_policy_with_cu(2_500);
    assert_cu_within("UpdateFeeRedirectPolicy", redirect_cu, CUSTODY_CU_LIMIT);
    let (cfg, _) = env.market_state();
    assert_eq!(cfg.fee_redirect_to_market_0_bps, 2_500);

    let secondary_mint = env.create_mint();
    let base_unit_cu = env.update_base_unit_mints_with_cu(env.mint, secondary_mint);
    assert_cu_within("UpdateBaseUnitMints", base_unit_cu, CUSTODY_CU_LIMIT);
    let (cfg, _) = env.market_state();
    assert_eq!(cfg.collateral_mint, env.mint.to_bytes());
    assert_eq!(cfg.secondary_collateral_mint, secondary_mint.to_bytes());

    let primary_source = env.token_account_for_mint(env.mint, env.admin.pubkey(), 50);
    let secondary_dest = env.token_account_for_mint(secondary_mint, env.admin.pubkey(), 0);
    // F-VAULT-FRAG fix: the secondary vault must be the canonical ATA of (vault_authority, secondary_mint).
    let secondary_vault = canonical_vault_ata(env.vault_authority, secondary_mint);
    env.svm
        .set_account(
            secondary_vault,
            Account {
                lamports: 1_000_000_000,
                data: make_token_data(secondary_mint, env.vault_authority, 50),
                owner: spl_token::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    let before_swap_market = env.svm.get_account(&env.market).unwrap().data;
    let swap_cu = env.swap_secondary_for_primary_with_cu(
        primary_source,
        env.vault,
        secondary_dest,
        secondary_vault,
        50,
    );
    assert_cu_within("SwapSecondaryForPrimary", swap_cu, CUSTODY_CU_LIMIT);
    assert_eq!(env.token_amount(primary_source), 0);
    assert_eq!(env.token_amount(env.vault), 50);
    assert_eq!(env.token_amount(secondary_dest), 50);
    assert_eq!(env.token_amount(secondary_vault), 0);
    assert_eq!(
        env.svm.get_account(&env.market).unwrap().data,
        before_swap_market,
        "base-unit swap must only move SPL custody"
    );

    let new_asset_authority = Keypair::new();
    let authority_cu = env.update_asset_authority_with_cu(&new_asset_authority);
    assert_cu_within("UpdateAuthority", authority_cu, CUSTODY_CU_LIMIT);
    let (cfg, _) = env.market_state();
    assert_eq!(cfg.marketauth, new_asset_authority.pubkey().to_bytes());
}

#[test]
fn v16_bpf_accounting_ledger_tags_are_bounded_and_update_state() {
    let mut env = V16CuEnv::new();
    let ledger = env.backing_domain_ledger_account();
    let (backing_source, top_up_cu) =
        env.top_up_backing_bucket_with_ledger_with_cu(ledger, 1, 100, 10);
    assert_cu_within(
        "TopUpBackingBucket ledger init",
        top_up_cu,
        CUSTODY_CU_LIMIT,
    );
    assert_eq!(env.token_amount(backing_source), 0);

    env.mutate_market(|_, group| {
        group.source_backing_buckets[1].utilization_fee_earnings = 30;
        group.vault += 30;
    });
    env.set_token_account_amount(env.vault, env.mint, env.vault_authority, 130);

    let sync_cu = env.sync_backing_domain_ledger_with_cu(ledger, 1);
    assert_cu_within("SyncBackingDomainLedger", sync_cu, CUSTODY_CU_LIMIT);
    let ledger_data = env.svm.get_account(&ledger).unwrap().data;
    let ledger_state = state::read_backing_domain_ledger(&ledger_data).unwrap();
    assert_eq!(ledger_state.total_principal_atoms, 100);
    assert_eq!(
        ledger_state.residual_received_atoms(),
        0,
        "principal top-up is not rewardable residual"
    );
    assert_eq!(ledger_state.last_observed_bucket_earnings_atoms, 30);
    assert_eq!(ledger_state.total_earnings_atoms, 30);
    assert_eq!(
        ledger_state.residual_received_atoms(),
        0,
        "utilization earnings are not rewardable residual"
    );

    let dest = env.token_account_for_mint(env.mint, env.admin.pubkey(), 0);
    let withdraw_earnings_cu =
        env.withdraw_backing_bucket_earnings_to_admin_token_with_cu(ledger, dest, 1, 20);
    assert_cu_within(
        "WithdrawBackingBucketEarnings",
        withdraw_earnings_cu,
        CUSTODY_CU_LIMIT,
    );
    assert_eq!(env.token_amount(dest), 20);
    let ledger_data = env.svm.get_account(&ledger).unwrap().data;
    let ledger_state = state::read_backing_domain_ledger(&ledger_data).unwrap();
    let (_, group) = env.market_state();
    assert_eq!(ledger_state.total_earnings_withdrawn_atoms, 20);
    assert_eq!(ledger_state.last_observed_bucket_earnings_atoms, 10);
    assert_eq!(
        ledger_state.residual_received_atoms(),
        0,
        "earnings withdrawal is not rewardable residual"
    );
    assert_eq!(group.source_backing_buckets[1].utilization_fee_earnings, 10);
    assert_eq!(group.vault, 110);

    let mut pnl_env = V16CuEnv::new();
    let pnl_ledger = pnl_env.backing_domain_ledger_account();
    pnl_env.top_up_backing_bucket_with_ledger_with_cu(pnl_ledger, 1, 40, 10);
    let owner = Keypair::new();
    let portfolio = pnl_env.create_portfolio(&owner);
    pnl_env.add_source_positive_pnl(portfolio, 1, 40);
    pnl_env.crank(
        portfolio,
        ProgInstruction::PermissionlessCrank {
            action: 0,
            asset_index: 0,
            now_slot: 0,
            funding_rate_e9: 0,
            close_q: 0,
            fee_bps: 0,
            recovery_reason: 0,
        },
    );
    let convert_cu = pnl_env.convert_released_pnl_with_cu(&owner, portfolio, 40);
    assert_cu_within("ConvertReleasedPnl", convert_cu, CUSTODY_CU_LIMIT);
    let account = pnl_env.portfolio_state(portfolio);
    assert_eq!(account.capital, 40);
    pnl_env.sync_backing_domain_ledger_with_cu(pnl_ledger, 1);
    let ledger_data = pnl_env.svm.get_account(&pnl_ledger).unwrap().data;
    let ledger_state = state::read_backing_domain_ledger(&ledger_data).unwrap();
    assert_eq!(ledger_state.cumulative_loss_atoms, 40);
    assert_eq!(
        ledger_state.residual_received_atoms(),
        40,
        "farm-facing residual_received aliases the monotonic backing loss counter"
    );
    assert_eq!(
        ledger_state.residual_received_delta_since(0).unwrap(),
        40,
        "farm start/end snapshot delta is deterministic"
    );
    assert_eq!(ledger_state.last_observed_unavailable_principal_atoms, 40);

    let mut insurance_env = V16CuEnv::new();
    let insurance_ledger = insurance_env.insurance_ledger_account();
    let (_, insurance_top_up_cu) =
        insurance_env.top_up_insurance_with_ledger_with_cu(insurance_ledger, 100);
    assert_cu_within(
        "TopUpInsurance ledger init",
        insurance_top_up_cu,
        CUSTODY_CU_LIMIT,
    );
    let init_cu = insurance_env.sync_insurance_ledger_with_cu(insurance_ledger);
    assert_cu_within("SyncInsuranceLedger init", init_cu, CUSTODY_CU_LIMIT);
    let ledger_data = insurance_env
        .svm
        .get_account(&insurance_ledger)
        .unwrap()
        .data;
    let ledger_state = state::read_insurance_ledger(&ledger_data).unwrap();
    assert_eq!(ledger_state.total_principal_atoms, 100);
    assert_eq!(ledger_state.last_observed_insurance_atoms, 100);

    insurance_env.mutate_market(|_, group| {
        group.insurance += 30;
        group.vault += 30;
        group.insurance_domain_budget[0] += 15;
        group.insurance_domain_budget[1] += 15;
    });
    insurance_env.svm.expire_blockhash();
    let profit_cu = insurance_env.sync_insurance_ledger_with_cu(insurance_ledger);
    assert_cu_within("SyncInsuranceLedger profit", profit_cu, CUSTODY_CU_LIMIT);
    let ledger_data = insurance_env
        .svm
        .get_account(&insurance_ledger)
        .unwrap()
        .data;
    let ledger_state = state::read_insurance_ledger(&ledger_data).unwrap();
    assert_eq!(ledger_state.cumulative_profit_atoms, 30);
    assert_eq!(ledger_state.last_observed_insurance_atoms, 130);

    insurance_env.mutate_market(|_, group| {
        group.insurance -= 20;
        group.vault -= 20;
        group.insurance_domain_budget[0] -= 10;
        group.insurance_domain_budget[1] -= 10;
    });
    insurance_env.svm.expire_blockhash();
    let loss_cu = insurance_env.sync_insurance_ledger_with_cu(insurance_ledger);
    assert_cu_within("SyncInsuranceLedger loss", loss_cu, CUSTODY_CU_LIMIT);
    let ledger_data = insurance_env
        .svm
        .get_account(&insurance_ledger)
        .unwrap()
        .data;
    let ledger_state = state::read_insurance_ledger(&ledger_data).unwrap();
    assert_eq!(ledger_state.cumulative_loss_atoms, 20);
    assert_eq!(ledger_state.last_observed_insurance_atoms, 110);
}

#[derive(Clone, Copy, Debug)]
enum BackingResidualCounterTradePath {
    TradeNoCpi,
    TradeCpi,
    BatchTradeNoCpi,
    BatchTradeCpi,
}

#[derive(Clone, Copy, Debug)]
enum AccountResidualCounterTradePath {
    TradeNoCpi,
    TradeCpi,
    BatchTradeNoCpi,
    BatchTradeCpi,
}

fn auth_matcher_for_lp_via_system_create(
    env: &mut V16CuEnv,
    lp_owner: &Keypair,
    lp_account: Pubkey,
) -> (Pubkey, Pubkey, Pubkey) {
    let matcher_program = Pubkey::new_unique();
    let matcher_bytes = std::fs::read(auth_matcher_program_path()).expect("read auth matcher BPF");
    env.svm.add_program(matcher_program, &matcher_bytes);
    let (ctx, delegate, _) =
        env.init_auth_matcher_context_via_system_create(matcher_program, lp_owner, lp_account);
    (matcher_program, ctx, delegate)
}

#[allow(clippy::too_many_arguments)]
fn execute_account_residual_counter_trade_path(
    env: &mut V16CuEnv,
    path: AccountResidualCounterTradePath,
    taker_owner: &Keypair,
    taker_account: Pubkey,
    lp_owner: &Keypair,
    lp_account: Pubkey,
    size_q: i128,
    exec_price: u64,
) -> u64 {
    env.svm.expire_blockhash();
    match path {
        AccountResidualCounterTradePath::TradeNoCpi => env.trade_asset_with_cu(
            0,
            taker_owner,
            taker_account,
            lp_owner,
            lp_account,
            size_q,
            exec_price,
            0,
        ),
        AccountResidualCounterTradePath::TradeCpi => {
            let (matcher_program, ctx, delegate) =
                auth_matcher_for_lp_via_system_create(env, lp_owner, lp_account);
            env.trade_cpi_with_cu_on_asset(
                taker_owner,
                taker_account,
                lp_owner,
                lp_account,
                matcher_program,
                ctx,
                delegate,
                0,
                size_q,
                0,
            )
        }
        AccountResidualCounterTradePath::BatchTradeNoCpi => env
            .send(
                ProgInstruction::BatchTradeNoCpi {
                    legs: vec![BatchTradeLeg {
                        asset_index: 0,
                        size_q,
                        exec_price,
                        fee_bps: 0,
                    }],
                },
                vec![
                    AccountMeta::new(taker_owner.pubkey(), true),
                    AccountMeta::new(lp_owner.pubkey(), true),
                    AccountMeta::new(env.market, false),
                    AccountMeta::new(taker_account, false),
                    AccountMeta::new(lp_account, false),
                ],
                &[taker_owner, lp_owner],
            )
            .expect("BatchTradeNoCpi account residual-counter trade"),
        AccountResidualCounterTradePath::BatchTradeCpi => {
            let (matcher_program, ctx, delegate) =
                auth_matcher_for_lp_via_system_create(env, lp_owner, lp_account);
            env.send(
                ProgInstruction::BatchTradeCpi {
                    legs: vec![BatchTradeCpiLeg {
                        asset_index: 0,
                        size_q,
                        fee_bps: 0,
                        limit_price: 0,
                    }],
                },
                vec![
                    AccountMeta::new(taker_owner.pubkey(), true),
                    AccountMeta::new(env.market, false),
                    AccountMeta::new(taker_account, false),
                    AccountMeta::new(lp_account, false),
                    AccountMeta::new_readonly(matcher_program, false),
                    AccountMeta::new(ctx, false),
                    AccountMeta::new_readonly(delegate, false),
                ],
                &[taker_owner],
            )
            .expect("BatchTradeCpi account residual-counter trade")
        }
    }
}

fn run_account_residual_counter_credit_case(
    path: AccountResidualCounterTradePath,
    size_q: i128,
    crystallized_loss_atoms: u128,
    expected_credit: u128,
) {
    const PRICE: u64 = 1_000;
    let mut env = V16CuEnv::new_with_market_params_and_price_move(2, 500, 500, 24);
    env.configure_auth_mark_for_asset_as_admin(0, 1, PRICE);
    let taker_owner = Keypair::new();
    let lp_owner = Keypair::new();
    let taker_account = env.create_portfolio(&taker_owner);
    let lp_account = env.create_portfolio(&lp_owner);
    env.deposit(&taker_owner, taker_account, 10_000);
    env.deposit(&lp_owner, lp_account, 10_000);

    let taker_initial = env.portfolio_state(taker_account);
    let lp_initial = env.portfolio_state(lp_account);
    assert_eq!(taker_initial.residual_crystallized_loss_atoms_total, 0);
    assert_eq!(taker_initial.residual_spent_principal_atoms_total, 0);
    assert_eq!(taker_initial.residual_received_atoms_total, 0);
    assert_eq!(lp_initial.residual_received_atoms_total, 0);

    env.set_residual_reward_counters_for_test(taker_account, crystallized_loss_atoms, 0, 0);
    let cu = execute_account_residual_counter_trade_path(
        &mut env,
        path,
        &taker_owner,
        taker_account,
        &lp_owner,
        lp_account,
        size_q,
        PRICE,
    );
    assert_cu_within(
        &format!("{path:?} account residual-counter trade"),
        cu,
        MULTI_ASSET_OPEN_TRADE_CU_LIMIT,
    );

    let taker_after = env.portfolio_state(taker_account);
    let lp_after = env.portfolio_state(lp_account);
    assert_eq!(
        taker_after.residual_crystallized_loss_atoms_total, crystallized_loss_atoms,
        "{path:?}: trading consumes reward budget but never reduces crystallized loss"
    );
    assert_eq!(
        taker_after.residual_spent_principal_atoms_total, expected_credit,
        "{path:?}: taker spends only real principal from the residual budget"
    );
    assert_eq!(
        taker_after.residual_received_atoms_total, 0,
        "{path:?}: the source trader does not self-credit LP rewards"
    );
    assert_eq!(
        lp_after.residual_received_atoms_total, expected_credit,
        "{path:?}: LP receives the deterministic residual credit"
    );
    assert_eq!(
        lp_after.residual_spent_principal_atoms_total, 0,
        "{path:?}: passive LP did not spend its own residual budget"
    );
    assert_ne!(
        lp_after.residual_received_atoms_total, PRICE as u128,
        "{path:?}: counter must not credit leveraged notional"
    );
}

#[test]
fn v16_bpf_account_residual_reward_counter_covers_all_trade_paths() {
    for path in [
        AccountResidualCounterTradePath::TradeNoCpi,
        AccountResidualCounterTradePath::TradeCpi,
        AccountResidualCounterTradePath::BatchTradeNoCpi,
        AccountResidualCounterTradePath::BatchTradeCpi,
    ] {
        run_account_residual_counter_credit_case(path, POS_SCALE as i128, 10_000, 50);
        run_account_residual_counter_credit_case(path, -(POS_SCALE as i128), 10_000, 50);
    }
}

#[test]
fn v16_bpf_account_residual_reward_counter_caps_available_crystallized_loss() {
    for path in [
        AccountResidualCounterTradePath::TradeNoCpi,
        AccountResidualCounterTradePath::TradeCpi,
        AccountResidualCounterTradePath::BatchTradeNoCpi,
        AccountResidualCounterTradePath::BatchTradeCpi,
    ] {
        run_account_residual_counter_credit_case(path, POS_SCALE as i128, 30, 30);
    }
}

#[test]
fn v16_bpf_account_residual_reward_counter_accumulates_across_batch_legs() {
    const PRICE: u64 = 1_000;
    for cpi in [false, true] {
        let mut env = V16CuEnv::new_with_market_params_and_price_move(2, 500, 500, 24);
        env.configure_auth_mark_for_asset_as_admin(0, 1, PRICE);
        env.configure_auth_mark_for_asset_as_admin(1, 1, PRICE);
        let taker_owner = Keypair::new();
        let lp_owner = Keypair::new();
        let taker_account = env.create_portfolio(&taker_owner);
        let lp_account = env.create_portfolio(&lp_owner);
        env.deposit(&taker_owner, taker_account, 10_000);
        env.deposit(&lp_owner, lp_account, 10_000);
        env.set_residual_reward_counters_for_test(taker_account, 10_000, 0, 0);
        env.svm.expire_blockhash();
        let cu = if cpi {
            let (matcher_program, ctx, delegate) =
                auth_matcher_for_lp_via_system_create(&mut env, &lp_owner, lp_account);
            env.send(
                ProgInstruction::BatchTradeCpi {
                    legs: vec![
                        BatchTradeCpiLeg {
                            asset_index: 0,
                            size_q: POS_SCALE as i128,
                            fee_bps: 0,
                            limit_price: 0,
                        },
                        BatchTradeCpiLeg {
                            asset_index: 1,
                            size_q: -(POS_SCALE as i128),
                            fee_bps: 0,
                            limit_price: 0,
                        },
                    ],
                },
                vec![
                    AccountMeta::new(taker_owner.pubkey(), true),
                    AccountMeta::new(env.market, false),
                    AccountMeta::new(taker_account, false),
                    AccountMeta::new(lp_account, false),
                    AccountMeta::new_readonly(matcher_program, false),
                    AccountMeta::new(ctx, false),
                    AccountMeta::new_readonly(delegate, false),
                ],
                &[&taker_owner],
            )
            .expect("BatchTradeCpi residual counters must accumulate across legs")
        } else {
            env.send(
                ProgInstruction::BatchTradeNoCpi {
                    legs: vec![
                        BatchTradeLeg {
                            asset_index: 0,
                            size_q: POS_SCALE as i128,
                            exec_price: PRICE,
                            fee_bps: 0,
                        },
                        BatchTradeLeg {
                            asset_index: 1,
                            size_q: -(POS_SCALE as i128),
                            exec_price: PRICE,
                            fee_bps: 0,
                        },
                    ],
                },
                vec![
                    AccountMeta::new(taker_owner.pubkey(), true),
                    AccountMeta::new(lp_owner.pubkey(), true),
                    AccountMeta::new(env.market, false),
                    AccountMeta::new(taker_account, false),
                    AccountMeta::new(lp_account, false),
                ],
                &[&taker_owner, &lp_owner],
            )
            .expect("BatchTradeNoCpi residual counters must accumulate across legs")
        };
        assert_cu_within(
            "two-leg residual-counter batch",
            cu,
            MULTI_ASSET_OPEN_TRADE_CU_LIMIT,
        );
        let taker_after = env.portfolio_state(taker_account);
        let lp_after = env.portfolio_state(lp_account);
        assert_eq!(
            taker_after.residual_spent_principal_atoms_total, 100,
            "two 50-atom principal increases spend exactly 100 atoms"
        );
        assert_eq!(
            lp_after.residual_received_atoms_total, 100,
            "batch LP receives the sum of per-leg real-principal credits"
        );
    }
}

#[test]
fn v16_attack_account_residual_spent_above_crystallized_rejects_trade_without_mutation() {
    for bad_taker in [true, false] {
        let mut env = V16CuEnv::new_with_market_params_and_price_move(1, 500, 500, 24);
        env.configure_auth_mark_for_asset_as_admin(0, 1, 1_000);
        let taker_owner = Keypair::new();
        let lp_owner = Keypair::new();
        let taker_account = env.create_portfolio(&taker_owner);
        let lp_account = env.create_portfolio(&lp_owner);
        env.deposit(&taker_owner, taker_account, 10_000);
        env.deposit(&lp_owner, lp_account, 10_000);
        let bad_account = if bad_taker { taker_account } else { lp_account };
        env.set_residual_reward_counters_for_test(bad_account, 10, 11, 0);
        let market_before = env.market_state().1;
        let taker_before = env.portfolio_state(taker_account);
        let lp_before = env.portfolio_state(lp_account);

        env.svm.expire_blockhash();
        let rejected = env.try_trade_asset_with_cu(
            0,
            &taker_owner,
            taker_account,
            &lp_owner,
            lp_account,
            POS_SCALE as i128,
            1_000,
            0,
        );
        assert!(
            rejected.is_err(),
            "spent > crystallized must reject before a trade can use malformed counters"
        );
        assert_eq!(env.portfolio_state(taker_account), taker_before);
        assert_eq!(env.portfolio_state(lp_account), lp_before);
        let market_after = env.market_state().1;
        assert_eq!(
            market_after.assets[0].oi_eff_long_q,
            market_before.assets[0].oi_eff_long_q
        );
        assert_eq!(
            market_after.assets[0].oi_eff_short_q,
            market_before.assets[0].oi_eff_short_q
        );
        assert_eq!(market_after.vault, market_before.vault);
    }
}

